// Concurrency control: run independent work in parallel, not sequentially.

// SLOW: sequential — total time = sum of both
async function sequential() {
  const a = await fetchUser();   // waits
  const b = await fetchOrders(); // then waits again
  return { a, b };
}

// FAST: concurrent — total time = max of both
async function concurrent() {
  const [a, b] = await Promise.all([fetchUser(), fetchOrders()]);
  return { a, b };
}

