function throttle(fn, intervalMs) {
  let last = 0;
  let timer = null;
  return function (...args) {
    const now = Date.now();
    const remaining = intervalMs - (now - last);
    if (remaining <= 0) {            // enough time passed: fire leading edge
      clearTimeout(timer); timer = null;
      last = now;
      fn.apply(this, args);
    } else if (!timer) {             // schedule trailing edge
      timer = setTimeout(() => { last = Date.now(); timer = null; fn.apply(this, args); }, remaining);
    }
  };
}

// BEFORE — leak: a new closure added on every request, never removed.
function handleRequest(req, res, bus) {
  const big = buildLargePayload(req); // captured by the closure below
  bus.on('flush', () => res.write(big)); // listener accumulates forever
}

// AFTER — bounded: register, then guarantee removal.
function handleRequest(req, res, bus) {
  const big = buildLargePayload(req);
  const onFlush = () => res.write(big);
  bus.on('flush', onFlush);
  res.on('close', () => bus.off('flush', onFlush)); // detach -> closure & payload collectable
}

// Anti-pattern: await inside a for loop -> N round-trips back to back
