function debounce(fn, wait, { immediate = false } = {}) {
  let timer = null;

  function debounced(...args) {
    const callNow = immediate && timer === null;

    clearTimeout(timer);
    timer = setTimeout(() => {
      timer = null;
      if (!immediate) fn.apply(this, args); // trailing edge
    }, wait);

    if (callNow) fn.apply(this, args);      // leading edge
  }

  debounced.cancel = () => {
    clearTimeout(timer);
    timer = null;
  };

  return debounced;
}

// Usage
const onSearch = debounce((q) => console.log('search', q), 300);
onSearch('a'); onSearch('ab'); onSearch('abc'); // -> logs once: 'search abc'

async function asyncPool(limit, items, iteratorFn) {
  const results = new Array(items.length);
  const executing = new Set();

  for (let i = 0; i < items.length; i++) {
    const idx = i;
    const p = Promise.resolve(iteratorFn(items[idx], idx))
      .then((res) => { results[idx] = res; });

    // Track the promise; remove itself from the in-flight set when settled.
    const tracked = p.then(() => executing.delete(tracked));
    executing.add(tracked);

    // Once we hit the limit, wait for the fastest in-flight task to finish.
    if (executing.size >= limit) {
      await Promise.race(executing); // rejects fast-fail if any task rejects
    }
  }

  await Promise.all(executing); // drain the tail; propagates any late rejection
  return results;
}

