function deepClone(value, seen = new WeakMap()) {
  // Primitives and functions: return as-is.
  if (value === null || typeof value !== 'object') return value;

  // Cycle / shared-reference guard.
  if (seen.has(value)) return seen.get(value);

  if (value instanceof Date) return new Date(value.getTime());
  if (value instanceof RegExp) return new RegExp(value.source, value.flags);

  if (value instanceof Map) {
    const out = new Map();
    seen.set(value, out);
    for (const [k, v] of value) out.set(deepClone(k, seen), deepClone(v, seen));
    return out;
  }
  if (value instanceof Set) {
    const out = new Set();
    seen.set(value, out);
    for (const v of value) out.add(deepClone(v, seen));
    return out;
  }

  const out = Array.isArray(value) ? [] : {};
  seen.set(value, out); // register BEFORE recursing so cycles resolve
  for (const key of Reflect.ownKeys(value)) {
    out[key] = deepClone(value[key], seen);
  }
  return out;
}

// Cycle test
const a = { name: 'a' };
a.self = a;
const clone = deepClone(a);
console.log(clone.self === clone);   // true — cycle preserved, no stack overflow
console.log(clone !== a);            // true — actually a copy
